#include <bits/stdc++.h>
#define int long long
using namespace std;
int qpow (int a, int b, int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
int exgcd (int a, int b, int &x, int &y) {
	if (b == 0) {
		x = 1;
		y = 0;
		return a;
	}
	int g = exgcd (b, a % b, x, y);
	int t = x;
	x = y;
	y = t - a / b * y;
	return g;
}
int EXBSGS (int a, int b, int p) {
	a %= p;
	b %= p;
	if (b == 1 || p == 1) {
		return 0;
	}
	int d, k = 0, A = 1;
	while (true) {
		d = __gcd (a, p);
		if (d == 1) {
			break;
		}
		if (b % d != 0) {
			return -1;
		}
		k++;
		b /= d;
		p /= d;
		A = A * (a / d) % p;
		if (A == b) {
			return k;
		}
	}
	int m = ceil (sqrt (p));
	int t = b;
	unordered_map <int, int> mp;
	for (int i = 0; i < m; i++) {
		mp[t] = i;
		t = t * a % p;
	}
	int mi = qpow (a, m, p);
	t = A;
	for (int i = 1; i <= m; i++) {
		t = t * mi % p;
		if (mp.count (t)) {
			return i * m - mp[t] + k;
		}
	}
	return -1;
}
