	int T, k;
	cin >> T >> k;
	while (T--) {
        int y, z, p;
		cin >> y >> z >> p;
		if (k == 1) {
			cout << qpow (y, z, p) << '\n';
		}
		if (k == 2) {
			int x0, y0;
			int g = exgcd (y, p, x0, y0);
			if (z % g != 0) {
				cout << "Orz, I cannot find x!\n";
			} else {
				int xmn = (x0 * z / g % (p / g) + p / g) % p / g;
				cout << xmn << "\n";
			}
		}
		if (k == 3) {
			int ans = EXBSGS (y, z, p);
			if (ans == -1) {
				cout << "Orz, I cannot find x!\n";
			} else {
				cout << ans << '\n';
			}
		}
	}
	return 0;
}
